// Set Inputs â€” Agent 8: Discovery Scorer
// Emits flat fields that Build Score Prompt consumes.
// Inputs are explicitly separated into three groups:
//   1. Job fields (the role being scored)
//   2. Target inputs â€” used ONLY by target dimension sub-scores
//   3. Background inputs â€” used ONLY by background dimension sub-scores
const trigger = $input.item.json;

function strip(val) {
  if (val === null || val === undefined) return '';
  if (typeof val !== 'string') return val;
  let cleaned = val;
  while (cleaned.length > 0 && cleaned.charAt(0) === '=') {
    cleaned = cleaned.substring(1);
  }
  return cleaned;
}

const config = trigger.config || {};
const systemPrompt = strip(trigger.system_prompt);

const provider = strip(config.provider_discovery_scorer);
if (!provider) throw new Error('[Agent 8] config.provider_discovery_scorer is required.');
const model = strip(config.model_discovery_scorer);
if (!model) throw new Error('[Agent 8] config.model_discovery_scorer is required.');
const maxTokens = Number(config.max_tokens_discovery_scorer);
if (!maxTokens || Number.isNaN(maxTokens)) {
  throw new Error('[Agent 8] config.max_tokens_discovery_scorer is required and must be a number.');
}

const num = (v) => {
  const n = Number(strip(v));
  return Number.isFinite(n) ? n : null;
};

const weightKeys = {
  title_match: 'weight_title_match',
  level_match: 'weight_level_match',
  role_type_match: 'weight_role_type_match',
  domain_match: 'weight_domain_match',
  location_match: 'weight_location_match',
  salary_signal: 'weight_salary_signal'
};
const weights = {};
const missingWeights = [];
for (const [dim, cfgKey] of Object.entries(weightKeys)) {
  const w = num(config[cfgKey]);
  if (w === null) missingWeights.push(cfgKey);
  weights[dim] = w === null ? 0 : w;
}
if (missingWeights.length > 0) {
  throw new Error(`[Agent 8] Missing/invalid weight config: ${missingWeights.join(', ')}.`);
}

const ts = num(config.discovery_threshold_strong_fit);
const tm = num(config.discovery_threshold_fit);
const tw = num(config.discovery_threshold_weak_fit);
if (ts === null || tm === null || tw === null) {
  throw new Error('[Agent 8] discovery_threshold_strong_match/_match/_weak_match are required numbers.');
}
const thresholds = { strong_fit: ts, fit: tm, weak_fit: tw };

// target_location falls back to applicant_location when blank, per config description
const targetLocation = strip(config.target_location) || strip(config.applicant_location) || '';
const targetCountry = strip(config.target_country) || '';
const targetEmploymentTypes = strip(config.employment_type_considered) || '';
const backgroundTitles = strip(config.background_titles) || '';

console.log(`[Agent 8 Set Inputs] job: ${trigger.company || 'unknown'} / ${trigger.title || 'unknown'}, master_doc: ${(trigger.master_doc || '').length} chars, provider: ${provider}, model: ${model}`);

return {
  json: {
    config,
    system_prompt: systemPrompt,
    provider,
    model,
    max_tokens: maxTokens,
    weights,
    thresholds,
    // â”€â”€ Job fields (the role being scored) â”€â”€
    company: trigger.company || '',
    title: trigger.title || '',
    location: trigger.location || '',
    remote: trigger.remote === true,
    description: trigger.description || '',
    posted_at: trigger.posted_at || '',
    // â”€â”€ Target inputs (the search) â€” used ONLY by target sub-scores â”€â”€
    target_titles: config.target_titles || '',
    target_location: targetLocation,
    target_country: targetCountry,
    employment_type_considered: targetEmploymentTypes,
    domain_interests: config.domain_interests || '',
    // â”€â”€ Background inputs (the candidate) â€” used ONLY by background sub-scores â”€â”€
    background_titles: backgroundTitles,
    profile_summary: config.profile_summary || '',
    master_doc: trigger.master_doc || ''
  }
};

const data = $input.item.json;

const OUTPUT_CONTRACT = `

Output EXACTLY this JSON. No preamble, no markdown fences, no commentary:

{
  "dimensions": {
    "title_match":      { "target": <integer 0-10 or "missing">, "background": <integer 0-10 or "missing"> },
    "level_match":      { "target": <integer 0-10 or "missing">, "background": <integer 0-10 or "missing"> },
    "role_type_match":  { "target": <integer 0-10 or "missing">, "background": <integer 0-10 or "missing"> },
    "domain_match":     { "target": <integer 0-10 or "missing">, "background": <integer 0-10 or "missing"> },
    "location_match":   { "target": <integer 0-10 or "missing">, "background": <integer 0-10 or "missing"> },
    "salary_signal":    { "target": <integer 0-10 or "missing">, "background": <integer 0-10 or "missing"> }
  },
  "restrictions": [
    { "type": "<short free-form label>", "detail": "<one sentence>", "severity": "hard|soft" }
  ],
  "strengths": {
    "target":     ["<concrete target-anchored strength>", "..."],
    "background": ["<concrete background-anchored strength>", "..."]
  },
  "gaps": {
    "target":     ["<concrete target-anchored gap>", "..."],
    "background": ["<concrete background-anchored gap>", "..."]
  },
  "rationale": "<1-2 sentence summary that names any divergence between target and background fit>"
}

== PER-DIMENSION SEMANTICS ==

target     = degree to which the job matches the CANDIDATE TARGETS block (the search criteria). Independent of who the candidate actually is.
background = degree to which the job matches the CANDIDATE BACKGROUND block (career evidence). Independent of what they searched for.

domain_match calibration (apply to BOTH target and background, each against its own block's domain signal):
- full match on the primary domain                       => 8-10
- partial match: job hits 1 of several listed interests  => 5-7
- adjacent / tangential domain                           => 3-4
- unrelated domain                                       => 0-2
- no domain signal in the block (empty interests)        => 5 (neutral)
Example: domain_interests = "robotics, autonomous systems, saas" and the job is a SaaS company. That matches 1 of 3 listed interests => 5-7, NOT 3. Do not under-score partial matches.

location_match calibration (target and background MUST be equal â€” see special rule below):
- job location inside the target geography (or remote when remote is acceptable) => 9-10
- same metro / commutable / same country generic                                => 6-8
- different region, same country                                                => 3-5
- different country / explicitly excluded location                              => 0-2
Score location ONLY against the target_location / target_country config fields and the job's location + remote flag. Do NOT read location preferences out of profile_summary or master_doc.

Special rule for location_match: target and background MUST be equal. Location depends on the job and the search location, not on candidate history. If you find yourself giving them different values, you are wrong â€” re-score.

== INPUT ISOLATION (the most common error to avoid) ==

When scoring a "target" sub-score for ANY dimension, consult ONLY the CANDIDATE TARGETS block. Do NOT consult background_titles, profile_summary, or master_doc.

When scoring a "background" sub-score for ANY dimension, consult ONLY the CANDIDATE BACKGROUND block. Do NOT consult target_titles, target_location, target_country, employment_type_considered, or domain_interests.

A common failure mode: penalizing the target title score because the candidate is over- or under-leveled for the role. That belongs in background's level_match, not in target's title_match. The target score is about the SEARCH, not the CANDIDATE.

Worked example. CANDIDATE TARGETS: title="Software engineer", location="Bay Area". CANDIDATE BACKGROUND: career history shows 15 years VP/Director leadership. JOB: "Software Engineer, Web Infrastructure" in San Francisco.

Correct:
- title_match: target=9 (literal match), background=6 (engineer-adjacent but not their actual recent titles)
- level_match: target=8 (no seniority in target), background=2 (VP vs IC)
- role_type_match: target=9 (IC SWE matches "Software engineer"), background=4 (they've been managing, not building)
- domain_match: target=7 (target unspecified), background=3 (AI/ML, not web infra)
- location_match: target=10, background=10 (SF in Bay Area)

Incorrect (the actual failure to avoid):
- title_match: target=3, background=7 â€” this inverts the dimension by treating "VP/Director" career history as the search target.

== CONFIG PRIMACY ==

The CANDIDATE TARGETS block is sourced from explicit config fields and is AUTHORITATIVE for every target sub-score. If profile_summary or master_doc expresses a preference (location, remote, employment type, domain, seniority) that contradicts a config field, the CONFIG FIELD WINS for target scoring. profile_summary preferences are background context, not search criteria.

Worked example. target_location = "Bay Area" (config). profile_summary says "remote-first, fractional engagements preferred". The job is on-site in San Francisco.
- Correct target location_match: 10 â€” the job is in the Bay Area, which is the authoritative target. Ignore the "remote-first" line from profile_summary when scoring target.
- The "remote-first" preference may inform background or a soft restriction, but it does NOT lower the target location score.

If the config target field is blank/missing, fall back to neutral (5) rather than importing a preference from profile_summary.

== SELF-CHECK ==

Before emitting JSON, scan your dimensions:
1. If the target column and background column track each other within 1-2 points across every dimension, you collapsed the inputs â€” re-score with strict isolation. The two columns are designed to diverge.
2. Confirm location_match.target === location_match.background. If not, re-score.
3. Confirm no target sub-score was lowered because of career level, recent titles, or any preference found only in profile_summary/master_doc. If one was, re-score it against the TARGETS/config block alone.
4. Confirm domain_match did not under-score a partial (1-of-many) match â€” partials are 5-7, not 3-4.

== USAGE ==

Use the literal string "missing" for any sub-score the JD does not support â€” independently for target and background. Do NOT guess. Severity is "hard" or "soft" (use "hard" for disqualifying requirements). Empty arrays are allowed for strengths.target, strengths.background, gaps.target, gaps.background, and restrictions.`;

const system = (data.system_prompt || '') + OUTPUT_CONTRACT;

const user_message = `== CANDIDATE TARGETS (anchor for target sub-scores â€” DO NOT use for background sub-scores) ==
Target titles: ${data.target_titles}
Target location: ${data.target_location}
Target country: ${data.target_country}
Employment types considered: ${data.employment_type_considered}
Domain interests: ${data.domain_interests}

== CANDIDATE BACKGROUND (anchor for background sub-scores â€” DO NOT use for target sub-scores) ==
Profile summary: ${data.profile_summary}
Background titles: ${data.background_titles}
Career history:
${data.master_doc}

== JOB ==
Company: ${data.company}
Title: ${data.title}
Location: ${data.location}
Remote: ${data.remote ? 'yes' : 'no'}
Posted at: ${data.posted_at || '(not provided)'}

Job Description:
${data.description}

Score this job across the 6 dimensions, producing TWO independent sub-scores per dimension (target and background) per the OUTPUT contract. Anchor each sub-score on the matching input block above:

- target sub-scores answer "does this job match the SEARCH?" using ONLY the CANDIDATE TARGETS block.
- background sub-scores answer "does this job match the CANDIDATE?" using ONLY the CANDIDATE BACKGROUND block.
- The two sub-scores are independent and are expected to diverge. Common patterns: over-qualified (high target, low background), under-qualified (low target, high background), aligned (both high), miss (both low).

Ground strengths and gaps in concrete evidence from the posting and the relevant input block. Tag each strength/gap as target-anchored or background-anchored. If target and background fit diverge significantly, name the divergence in the rationale.`;

console.log(`[Agent 8 Build Prompt] system: ${system.length} chars, user: ${user_message.length} chars, master_doc: ${(data.master_doc || '').length} chars`);

return {
  json: {
    ...data,
    system,
    user_message
  }
};

// Agent 8: format output (Discovery Scorer)
// Mode: Run Once for All Items
// Dual scoring: each dimension has {target, background} sub-scores. Computes
// target_overall and background_overall using the same weight set, buckets each
// against the same thresholds. The "primary" overall_score / verdict mirror
// target-driven values so existing downstream consumers stay correct.

const callLLM = $('Call LLM').first().json;

const REQUIRED_DIMS = [
  'title_match', 'level_match', 'role_type_match',
  'domain_match', 'location_match', 'salary_signal'
];

const emptyResult = {
  overall_score: 0,
  background_overall_score: 0,
  verdict: 'no_fit',
  background_verdict: 'no_fit',
  dimensions: {},
  restrictions: [],
  strengths: { target: [], background: [] },
  gaps: { target: [], background: [] },
  rationale: ''
};

if (callLLM.success === false) {
  console.log(`[Agent 8] LLM call failed: ${callLLM.error?.category || 'unknown'} â€” ${callLLM.error?.message || 'no message'}`);
  return {
    json: {
      success: false,
      ...emptyResult,
      tokens: { input: callLLM.input_tokens || 0, output: callLLM.output_tokens || 0 },
      cached_input_tokens: callLLM.cached_input_tokens || 0,
      cache_write_tokens: callLLM.cache_write_tokens || 0,
      model_used: callLLM.model_used || 'unknown',
      provider_used: callLLM.provider_used || 'unknown',
      errors: [...(callLLM.errors || [])],
      error: callLLM.error || {
        category: 'unknown',
        type: 'unknown',
        message: 'Call LLM returned success: false with no error object',
        provider: callLLM.provider_used || 'unknown',
        model: callLLM.model_used || 'unknown'
      }
    }
  };
}

const response = $input.item.json;
const text = response.text || response.content || response.response || response.output_text || response.completion || '';

const parseErrors = [];
let parsed = null;
let errorType = 'json_parse_failure';

const tryParse = (str) => {
  try { return JSON.parse(str); } catch (e) { return null; }
};

if (!text) {
  parseErrors.push(`No text returned from Call LLM. Keys: ${Object.keys(response).join(', ')}`);
  errorType = 'empty_output';
  console.log(`[Agent 8] ${parseErrors[parseErrors.length - 1]}`);
} else {
  const rawText = String(text);
  let cleaned = rawText.replace(/^```(?:json)?\s*/i, '').replace(/\s*```\s*$/i, '').trim();
  parsed = tryParse(cleaned);
  if (!parsed) {
    const firstBrace = cleaned.indexOf('{');
    const lastBrace = cleaned.lastIndexOf('}');
    if (firstBrace !== -1 && lastBrace > firstBrace) {
      parsed = tryParse(cleaned.substring(firstBrace, lastBrace + 1));
    }
  }
  if (!parsed) {
    parseErrors.push(`Could not parse JSON. Start: ${rawText.substring(0, 300)}`);
    console.log(`[Agent 8] JSON parse failed. Raw content (first 500 chars):\n${rawText.slice(0, 500)}`);
  } else {
    const dims = parsed.dimensions || {};
    const missing = REQUIRED_DIMS.filter(d => !(d in dims));
    if (missing.length > 0) {
      parseErrors.push(`Missing dimensions: ${missing.join(', ')}`);
      errorType = 'schema_violation';
      console.log(`[Agent 8] ${parseErrors[parseErrors.length - 1]}`);
      parsed = null;
    } else {
      const badShape = REQUIRED_DIMS.filter(d => {
        const v = dims[d];
        return !(v && typeof v === 'object' && ('target' in v) && ('background' in v));
      });
      if (badShape.length > 0) {
        parseErrors.push(`Dimensions missing target/background sub-scores: ${badShape.join(', ')}`);
        errorType = 'schema_violation';
        console.log(`[Agent 8] ${parseErrors[parseErrors.length - 1]}`);
        parsed = null;
      }
    }
  }
}

const success = parsed !== null;
let error = null;
let target_overall = 0;
let background_overall = 0;
let verdict = 'no_fit';
let background_verdict = 'no_fit';
let dims = {};

const scoreNum = (raw) => (typeof raw === 'number' && isFinite(raw)) ? raw : 0;
const bucketize = (s, t) => {
  if (s >= t.strong_fit) return 'strong_fit';
  if (s >= t.fit) return 'fit';
  if (s >= t.weak_fit) return 'weak_fit';
  return 'no_fit';
};

if (success) {
  dims = parsed.dimensions || {};
  const weights = $('Set Inputs').first().json.weights;
  const thresholds = $('Set Inputs').first().json.thresholds;

  let targetSum = 0;
  let backgroundSum = 0;
  for (const d of REQUIRED_DIMS) {
    const w = weights[d] || 0;
    targetSum += w * scoreNum(dims[d].target);
    backgroundSum += w * scoreNum(dims[d].background);
  }
  target_overall = Math.round(targetSum * 10);
  background_overall = Math.round(backgroundSum * 10);
  verdict = bucketize(target_overall, thresholds);
  background_verdict = bucketize(background_overall, thresholds);
} else {
  error = {
    category: 'output_quality',
    type: errorType,
    message: parseErrors.join('; ') || 'Could not parse scorer output',
    provider: callLLM.provider_used || 'unknown',
    model: callLLM.model_used || 'unknown'
  };
}

const sanitizeStrGap = (obj) => {
  if (obj && typeof obj === 'object' && !Array.isArray(obj)) {
    return {
      target: Array.isArray(obj.target) ? obj.target : [],
      background: Array.isArray(obj.background) ? obj.background : []
    };
  }
  return { target: [], background: [] };
};

console.log(`[Agent 8] target_overall=${target_overall} (${verdict}), background_overall=${background_overall} (${background_verdict})`);
console.log(`[Agent 8] Tokens: ${callLLM.input_tokens || 0}in + ${callLLM.output_tokens || 0}out + ${callLLM.cached_input_tokens || 0}cached + ${callLLM.cache_write_tokens || 0}cache_write`);

return {
  json: {
    success,
    overall_score: target_overall,
    background_overall_score: background_overall,
    verdict,
    background_verdict,
    dimensions: dims,
    restrictions: success && Array.isArray(parsed.restrictions) ? parsed.restrictions : [],
    strengths: sanitizeStrGap(success ? parsed.strengths : null),
    gaps: sanitizeStrGap(success ? parsed.gaps : null),
    rationale: success ? (parsed.rationale || '') : '',
    tokens: { input: callLLM.input_tokens || 0, output: callLLM.output_tokens || 0 },
    cached_input_tokens: callLLM.cached_input_tokens || 0,
    cache_write_tokens: callLLM.cache_write_tokens || 0,
    model_used: callLLM.model_used || 'unknown',
    provider_used: callLLM.provider_used || 'unknown',
    errors: parseErrors,
    error
  }
};
